const DEFAULT_CATEGORIES = ['เครื่องมือช่าง', 'อาหาร', 'เครื่องครัว', 'ของใช้ในบ้าน', 'เฟอร์นิเจอร์', 'บิวตี้', 'แฟชั่น', 'อิเล็กทรอนิกส์', 'สุขภาพ', 'กีฬา', 'สัตว์เลี้ยง', 'ยานยนต์', 'อื่นๆ']

async function getCategories(bucket: R2Bucket): Promise<string[]> {
    const obj = await bucket.get('_config/categories.json')
    if (obj) return await obj.json() as string[]
    return DEFAULT_CATEGORIES
}

function toThaiDateString(value: string | Date): string {
    const date = value instanceof Date ? value : new Date(value)
    if (Number.isNaN(date.getTime())) return ''
    const thai = new Date(date.getTime() + (7 * 60 * 60 * 1000))
    return thai.toISOString().split('T')[0]
}

function uniqueVideoIds(ids: string[]): string[] {
    const out: string[] = []
    const seen = new Set<string>()
    for (const raw of ids) {
        const id = String(raw || '').trim()
        if (!id || seen.has(id)) continue
        seen.add(id)
        out.push(id)
    }
    return out
}

function parseVideoCreatedAtMs(value: unknown): number {
    const ms = new Date(String(value || '')).getTime()
    return Number.isFinite(ms) ? ms : Number.POSITIVE_INFINITY
}

function dedupeVideosById(videos: any[]): any[] {
    const byId = new Map<string, any>()
    for (const video of videos || []) {
        const id = String(video?.id || '').trim()
        if (!id) continue
        const namespaceId = String(video?.namespace_id || '').trim()
        const key = namespaceId ? `${namespaceId}:${id}` : id
        const prev = byId.get(key)
        if (!prev) {
            byId.set(key, video)
            continue
        }
        const prevTs = new Date(String(prev?.updatedAt || prev?.createdAt || '')).getTime()
        const nextTs = new Date(String(video?.updatedAt || video?.createdAt || '')).getTime()
        if ((Number.isFinite(nextTs) ? nextTs : 0) >= (Number.isFinite(prevTs) ? prevTs : 0)) {
            byId.set(key, video)
        }
    }
    return Array.from(byId.values())
}

function getGalleryVideoSortMs(video: Record<string, unknown> | null | undefined): number {
    const ts = new Date(String(
        video?.processedAt
        || video?.processed_at
        || video?.postedAt
        || video?.posted_at
        || video?.updatedAt
        || video?.updated_at
        || video?.createdAt
        || video?.created_at
        || ''
    )).getTime()
    return Number.isFinite(ts) ? ts : 0
}

function pickOldestGalleryVideoForPosting(videos: Array<Record<string, unknown>>): Record<string, unknown> | null {
    let picked: Record<string, unknown> | null = null
    let pickedTs = Number.POSITIVE_INFINITY

    for (const video of videos || []) {
        const ts = getGalleryVideoSortMs(video)
        if (!picked) {
            picked = video
            pickedTs = ts
            continue
        }

        if (ts < pickedTs) {
            picked = video
            pickedTs = ts
            continue
        }

        if (ts === pickedTs) {
            const pickedId = String(picked.id || '').trim()
            const nextId = String(video.id || '').trim()
            if (nextId && (!pickedId || nextId.localeCompare(pickedId) < 0)) {
                picked = video
                pickedTs = ts
            }
        }
    }

    return picked
}

function pickNewestGalleryVideoForPosting(videos: Array<Record<string, unknown>>): Record<string, unknown> | null {
    let picked: Record<string, unknown> | null = null
    let pickedTs = Number.NEGATIVE_INFINITY

    for (const video of videos || []) {
        const ts = getGalleryVideoSortMs(video)
        if (!picked) {
            picked = video
            pickedTs = ts
            continue
        }

        if (ts > pickedTs) {
            picked = video
            pickedTs = ts
            continue
        }

        if (ts === pickedTs) {
            const pickedId = String(picked.id || '').trim()
            const nextId = String(video.id || '').trim()
            if (nextId && (!pickedId || nextId.localeCompare(pickedId) > 0)) {
                picked = video
                pickedTs = ts
            }
        }
    }

    return picked
}

function pickRandomGalleryVideoForPostingOrder(videos: Array<Record<string, unknown>>): Record<string, unknown> | null {
    if (!Array.isArray(videos) || videos.length === 0) return null
    const index = Math.floor(Math.random() * videos.length)
    return videos[index] || null
}

type NamespacePostingOrder = 'oldest_first' | 'newest_first' | 'random'

function pickGalleryVideoForPostingByOrder(
    videos: Array<Record<string, unknown>>,
    postingOrder: NamespacePostingOrder,
): Record<string, unknown> | null {
    switch (postingOrder) {
        case 'newest_first':
            return pickNewestGalleryVideoForPosting(videos)
        case 'random':
            return pickRandomGalleryVideoForPostingOrder(videos)
        case 'oldest_first':
        default:
            return pickOldestGalleryVideoForPosting(videos)
    }
}

function orderGalleryVideosForPosting(
    videos: Array<Record<string, unknown>>,
    postingOrder: NamespacePostingOrder,
): Array<Record<string, unknown>> {
    const ordered = [...(videos || [])].filter((video) => !!String(video?.id || '').trim())
    if (postingOrder === 'random') {
        for (let index = ordered.length - 1; index > 0; index -= 1) {
            const swapIndex = Math.floor(Math.random() * (index + 1))
            const current = ordered[index]
            ordered[index] = ordered[swapIndex]
            ordered[swapIndex] = current
        }
        return ordered
    }

    ordered.sort((current, next) => {
        const currentTs = getGalleryVideoSortMs(current)
        const nextTs = getGalleryVideoSortMs(next)
        if (currentTs !== nextTs) {
            return postingOrder === 'newest_first'
                ? nextTs - currentTs
                : currentTs - nextTs
        }
        const currentId = String(current?.id || '').trim()
        const nextId = String(next?.id || '').trim()
        return postingOrder === 'newest_first'
            ? nextId.localeCompare(currentId)
            : currentId.localeCompare(nextId)
    })
    return ordered
}

async function getLatestSuccessfulPostHistoryRow(db: D1Database, params: {
    namespaceId: string
    pageId: string
    videoId: string
    sourceFingerprint?: string
}): Promise<{ id: number | null; fbPostId: string | null; postedAt: string | null } | null> {
    const namespaceId = String(params.namespaceId || '').trim()
    const pageId = String(params.pageId || '').trim()
    const videoId = String(params.videoId || '').trim()
    const sourceFingerprint = normalizeNamespaceVideoSourceFingerprint(params.sourceFingerprint)
    if (!namespaceId || !pageId || !videoId) return null

    const row = await db.prepare(
        `SELECT ph.id, ph.fb_post_id, ph.posted_at
         FROM post_history ph
         LEFT JOIN namespace_video_state nvs
           ON nvs.namespace_id = ph.bot_id
          AND nvs.video_id = ph.video_id
         WHERE ph.bot_id = ?
           AND ph.page_id = ?
           AND ph.status = 'success'
           AND (
               ph.video_id = ?
               OR (? <> '' AND COALESCE(NULLIF(TRIM(ph.source_fingerprint), ''), nvs.source_fingerprint) = ?)
           )
         ORDER BY datetime(ph.posted_at) DESC, ph.id DESC
         LIMIT 1`
    ).bind(namespaceId, pageId, videoId, sourceFingerprint, sourceFingerprint).first() as {
        id?: number
        fb_post_id?: string | null
        posted_at?: string | null
    } | null

    if (!row) return null
    return {
        id: typeof row.id === 'number' ? row.id : null,
        fbPostId: String(row.fb_post_id || '').trim() || null,
        postedAt: String(row.posted_at || '').trim() || null,
    }
}

async function ensurePagePostedVideoGuardsTable(db: D1Database): Promise<void> {
    await db.prepare(
        `CREATE TABLE IF NOT EXISTS page_posted_video_guards (
            guard_key TEXT PRIMARY KEY,
            bot_id TEXT NOT NULL,
            page_id TEXT NOT NULL,
            video_id TEXT NOT NULL DEFAULT '',
            source_fingerprint TEXT NOT NULL DEFAULT '',
            history_id INTEGER,
            created_at TEXT NOT NULL DEFAULT (datetime('now')),
            updated_at TEXT NOT NULL DEFAULT (datetime('now'))
        )`
    ).run()
    await db.prepare(
        'CREATE INDEX IF NOT EXISTS idx_page_posted_video_guards_page ON page_posted_video_guards(bot_id, page_id)'
    ).run()
}

async function ensurePagePostedVideoGuardsBackfilled(db: D1Database): Promise<void> {
    await ensurePostHistoryTraceColumns(db)
    await ensurePagePostedVideoGuardsTable(db)
    await db.prepare(
        `INSERT OR IGNORE INTO page_posted_video_guards (
            guard_key,
            bot_id,
            page_id,
            video_id,
            source_fingerprint,
            history_id,
            created_at,
            updated_at
        )
        SELECT
            'video::' || ph.bot_id || '::' || ph.page_id || '::' || ph.video_id,
            ph.bot_id,
            ph.page_id,
            ph.video_id,
            COALESCE(NULLIF(TRIM(ph.source_fingerprint), ''), ''),
            ph.id,
            ph.posted_at,
            ph.posted_at
        FROM post_history ph
        WHERE ph.status = 'success'
          AND TRIM(COALESCE(ph.video_id, '')) <> ''`
    ).run().catch(() => { })
    await db.prepare(
        `INSERT OR IGNORE INTO page_posted_video_guards (
            guard_key,
            bot_id,
            page_id,
            video_id,
            source_fingerprint,
            history_id,
            created_at,
            updated_at
        )
        SELECT
            'fingerprint::' || ph.bot_id || '::' || ph.page_id || '::' || COALESCE(NULLIF(TRIM(ph.source_fingerprint), ''), TRIM(nvs.source_fingerprint)),
            ph.bot_id,
            ph.page_id,
            ph.video_id,
            COALESCE(NULLIF(TRIM(ph.source_fingerprint), ''), TRIM(nvs.source_fingerprint)),
            ph.id,
            ph.posted_at,
            ph.posted_at
        FROM post_history ph
        LEFT JOIN namespace_video_state nvs
          ON nvs.namespace_id = ph.bot_id
         AND nvs.video_id = ph.video_id
        WHERE ph.status = 'success'
          AND TRIM(COALESCE(NULLIF(TRIM(ph.source_fingerprint), ''), nvs.source_fingerprint, '')) <> ''`
    ).run().catch(() => { })
}

function buildPagePostedVideoGuardKeys(params: {
    namespaceId: string
    pageId: string
    videoId: string
    sourceFingerprint?: string
}): string[] {
    const namespaceId = String(params.namespaceId || '').trim()
    const pageId = String(params.pageId || '').trim()
    const videoId = String(params.videoId || '').trim()
    const sourceFingerprint = normalizeNamespaceVideoSourceFingerprint(params.sourceFingerprint)
    if (!namespaceId || !pageId) return []

    const keys: string[] = []
    if (videoId) keys.push(`video::${namespaceId}::${pageId}::${videoId}`)
    if (sourceFingerprint) keys.push(`fingerprint::${namespaceId}::${pageId}::${sourceFingerprint}`)
    return keys
}

async function getExistingPagePostedVideoGuard(db: D1Database, params: {
    namespaceId: string
    pageId: string
    videoId: string
    sourceFingerprint?: string
}): Promise<{ historyId: number | null; createdAt: string | null } | null> {
    const keys = buildPagePostedVideoGuardKeys(params)
    if (keys.length === 0) return null
    await ensurePagePostedVideoGuardsBackfilled(db)
    const placeholders = keys.map(() => '?').join(', ')
    const row = await db.prepare(
        `SELECT p.history_id, p.created_at
         FROM page_posted_video_guards p
         LEFT JOIN namespace_video_state nvs
           ON nvs.namespace_id = p.bot_id
          AND nvs.video_id = p.video_id
         WHERE p.guard_key IN (${placeholders})
           AND (
               TRIM(COALESCE(nvs.manual_unposted_at, '')) = ''
               OR datetime(COALESCE(p.updated_at, p.created_at)) > datetime(nvs.manual_unposted_at)
           )
         ORDER BY datetime(p.updated_at) DESC, p.history_id DESC
         LIMIT 1`
    ).bind(...keys).first() as { history_id?: number | null; created_at?: string | null } | null
    if (!row) return null
    return {
        historyId: typeof row.history_id === 'number' ? row.history_id : null,
        createdAt: String(row.created_at || '').trim() || null,
    }
}

async function recordPagePostedVideoGuard(db: D1Database, params: {
    namespaceId: string
    pageId: string
    videoId: string
    sourceFingerprint?: string
    historyId?: number | null
    postedAt?: string | null
}): Promise<void> {
    const keys = buildPagePostedVideoGuardKeys(params)
    if (keys.length === 0) return
    await ensurePagePostedVideoGuardsBackfilled(db)
    const namespaceId = String(params.namespaceId || '').trim()
    const pageId = String(params.pageId || '').trim()
    const videoId = String(params.videoId || '').trim()
    const sourceFingerprint = normalizeNamespaceVideoSourceFingerprint(params.sourceFingerprint)
    const historyId = typeof params.historyId === 'number' ? params.historyId : null
    const postedAt = String(params.postedAt || '').trim() || new Date().toISOString()

    for (const guardKey of keys) {
        await db.prepare(
            `INSERT INTO page_posted_video_guards (
                guard_key,
                bot_id,
                page_id,
                video_id,
                source_fingerprint,
                history_id,
                created_at,
                updated_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?)
            ON CONFLICT(guard_key) DO UPDATE SET
                history_id = COALESCE(excluded.history_id, page_posted_video_guards.history_id),
                updated_at = excluded.updated_at`
        ).bind(
            guardKey,
            namespaceId,
            pageId,
            videoId,
            sourceFingerprint,
            historyId,
            postedAt,
            postedAt,
        ).run().catch(() => { })
    }
}

async function claimGalleryVideoForPosting(params: {
    db: D1Database
    namespaceId: string
    pageId: string
    videos: Array<Record<string, unknown>>
    postingOrder: NamespacePostingOrder
}): Promise<{ video: Record<string, unknown>; videoLockKey: string } | null> {
    const namespaceId = String(params.namespaceId || '').trim()
    const pageId = String(params.pageId || '').trim()
    if (!namespaceId || !pageId) return null

    const orderedVideos = orderGalleryVideosForPosting(params.videos, params.postingOrder)
    for (const video of orderedVideos) {
        const videoId = String(video?.id || '').trim()
        if (!videoId) continue
        const sourceFingerprint = normalizeNamespaceVideoSourceFingerprint(
            video?.sourceFingerprint || video?.source_fingerprint,
        )

        const existingGuard = await getExistingPagePostedVideoGuard(params.db, {
            namespaceId,
            pageId,
            videoId,
            sourceFingerprint,
        })
        if (existingGuard) {
            const latestHistory = await getLatestSuccessfulPostHistoryRow(params.db, {
                namespaceId,
                pageId,
                videoId,
                sourceFingerprint,
            })
            const postedAt = latestHistory?.postedAt || existingGuard.createdAt || new Date().toISOString()
            await markNamespaceVideoPosted(params.db, namespaceId, videoId, postedAt).catch(() => { })
            continue
        }

        const videoLockKey = await tryAcquirePostingLock(params.db, {
            scope: 'video',
            namespaceId,
            videoId,
        })
        if (!videoLockKey) continue

        return { video, videoLockKey }
    }

    return null
}

async function ensurePageVideoNeverPosted(params: {
    db: D1Database
    namespaceId: string
    pageId: string
    videoId: string
    sourceFingerprint?: string
}): Promise<{ ok: true } | { ok: false; postedAt: string | null; historyId: number | null }> {
    const existingGuard = await getExistingPagePostedVideoGuard(params.db, params)
    if (!existingGuard) return { ok: true }

    const latestHistory = await getLatestSuccessfulPostHistoryRow(params.db, params)
    const postedAt = latestHistory?.postedAt || existingGuard.createdAt || null
    await markNamespaceVideoPosted(params.db, params.namespaceId, params.videoId, postedAt || new Date().toISOString()).catch(() => { })
    return {
        ok: false,
        postedAt,
        historyId: latestHistory?.id ?? existingGuard.historyId ?? null,
    }
}

function hasGalleryVideoThumbnail(video: Record<string, unknown> | null | undefined): boolean {
    return !!String(
        video?.thumbnailUrl
        || video?.thumbnail_url
        || ''
    ).trim()
}

function pickPreferredSystemGalleryVideo(current: Record<string, unknown>, next: Record<string, unknown>): Record<string, unknown> {
    const getCommerceRank = (video: Record<string, unknown>) => {
        if (normalizeMetaLazadaLink(video)) return 2
        if (normalizeMetaShopeeLink(video)) return 1
        return 0
    }
    const currentLinkRank = getCommerceRank(current)
    const nextLinkRank = getCommerceRank(next)
    if (currentLinkRank !== nextLinkRank) {
        return nextLinkRank > currentLinkRank ? next : current
    }

    const currentHasThumbnail = hasGalleryVideoThumbnail(current)
    const nextHasThumbnail = hasGalleryVideoThumbnail(next)
    if (currentHasThumbnail !== nextHasThumbnail) {
        return nextHasThumbnail ? next : current
    }

    const currentTs = getGalleryVideoSortMs(current)
    const nextTs = getGalleryVideoSortMs(next)
    if (currentTs !== nextTs) {
        return nextTs >= currentTs ? next : current
    }

    const currentNamespaceId = String(current.namespace_id || '').trim()
    const nextNamespaceId = String(next.namespace_id || '').trim()
    return nextNamespaceId.localeCompare(currentNamespaceId) <= 0 ? next : current
}

function normalizeVideoDuplicateValue(value: unknown): string {
    return String(value || '').trim().replace(/#.*$/, '')
}

function getNamespaceVideoDuplicateKey(video: Record<string, unknown>): string {
    const namespaceId = String(video.namespace_id || video.namespaceId || '').trim()
    const originalUrl = normalizeVideoDuplicateValue(video.originalUrl || video.original_url)
    if (namespaceId && originalUrl) return `${namespaceId}::original::${originalUrl}`

    const sourceType = String(video.sourceType || video.source_type || '').trim().toLowerCase()
    const sourceLabel = normalizeVideoDuplicateValue(video.sourceLabel || video.source_label)
    const videoUrl = normalizeVideoDuplicateValue(video.videoUrl || video.video_url)
    const previewUrl = normalizeVideoDuplicateValue(video.previewUrl || video.preview_url)

    if (namespaceId && sourceType === 'xhs_url' && sourceLabel) return `${namespaceId}::xhs::${sourceLabel}`
    if (namespaceId && videoUrl) return `${namespaceId}::video::${videoUrl}`
    if (namespaceId && previewUrl) return `${namespaceId}::preview::${previewUrl}`
    return ''
}

function dedupeSystemGalleryVideos(videos: any[]): any[] {
    const byVideoId = new Map<string, Record<string, unknown>>()
    for (const rawVideo of videos || []) {
        const video = rawVideo as Record<string, unknown>
        const id = String(video?.id || '').trim()
        if (!id) continue
        const prev = byVideoId.get(id)
        if (!prev) {
            byVideoId.set(id, video)
            continue
        }
        byVideoId.set(id, pickPreferredSystemGalleryVideo(prev, video))
    }

    const bySourceKey = new Map<string, Record<string, unknown>>()
    for (const video of byVideoId.values()) {
        const sourceKey = getNamespaceVideoDuplicateKey(video)
        if (!sourceKey) {
            bySourceKey.set(`id::${String(video.id || '').trim()}`, video)
            continue
        }
        const previous = bySourceKey.get(sourceKey)
        if (!previous) {
            bySourceKey.set(sourceKey, video)
            continue
        }
        bySourceKey.set(sourceKey, pickPreferredSystemGalleryVideo(previous, video))
    }

    return Array.from(bySourceKey.values()).sort((a, b) => getGalleryVideoSortMs(b) - getGalleryVideoSortMs(a))
}

function getNamespaceInventoryGroupKey(video: Record<string, unknown>): string {
    const namespaceId = String(video.namespace_id || video.namespaceId || '').trim()
    const videoId = String(video.id || '').trim()
    const fingerprint = normalizeNamespaceVideoSourceFingerprint(
        video.sourceFingerprint || video.source_fingerprint
    )
    if (namespaceId && fingerprint) return `${namespaceId}::fingerprint::${fingerprint}`
    if (namespaceId && videoId) return `${namespaceId}::id::${videoId}`
    return videoId
}

function getPostedAtMs(video: Record<string, unknown>): number {
    const ts = new Date(String(video.postedAt || video.posted_at || '')).getTime()
    return Number.isFinite(ts) ? ts : 0
}

function pickPreferredNamespaceInventoryVideo(current: Record<string, unknown>, next: Record<string, unknown>): Record<string, unknown> {
    const currentPosted = isNamespaceGalleryVideoPosted(current)
    const nextPosted = isNamespaceGalleryVideoPosted(next)
    if (currentPosted !== nextPosted) {
        return currentPosted ? current : next
    }

    if (currentPosted && nextPosted) {
        const currentPostedAtMs = getPostedAtMs(current)
        const nextPostedAtMs = getPostedAtMs(next)
        if (currentPostedAtMs !== nextPostedAtMs) {
            return nextPostedAtMs >= currentPostedAtMs ? next : current
        }
    }

    const currentHasThumbnail = hasGalleryVideoThumbnail(current)
    const nextHasThumbnail = hasGalleryVideoThumbnail(next)
    if (currentHasThumbnail !== nextHasThumbnail) {
        return nextHasThumbnail ? next : current
    }

    const currentTs = getGalleryVideoSortMs(current)
    const nextTs = getGalleryVideoSortMs(next)
    if (currentTs !== nextTs) {
        return nextTs >= currentTs ? next : current
    }

    const currentId = String(current.id || '').trim()
    const nextId = String(next.id || '').trim()
    return nextId.localeCompare(currentId) >= 0 ? next : current
}

function dedupeNamespaceInventoryVideos(videos: Array<Record<string, unknown>>): Array<Record<string, unknown>> {
    const grouped = new Map<string, Record<string, unknown>>()
    for (const video of videos || []) {
        const key = getNamespaceInventoryGroupKey(video)
        if (!key) continue
        const previous = grouped.get(key)
        if (!previous) {
            grouped.set(key, video)
            continue
        }
        grouped.set(key, pickPreferredNamespaceInventoryVideo(previous, video))
    }
    return Array.from(grouped.values()).sort((a, b) => getGalleryVideoSortMs(b) - getGalleryVideoSortMs(a))
}

function shuffleInPlace<T>(items: T[]): T[] {
    for (let i = items.length - 1; i > 0; i -= 1) {
        const j = Math.floor(Math.random() * (i + 1))
        const tmp = items[i]
        items[i] = items[j]
        items[j] = tmp
    }
    return items
}

async function listAllVideoJsonIds(bucket: R2Bucket): Promise<string[]> {
    const objects = await listAllVideoObjects(bucket)
    const ids: string[] = []
    for (const obj of objects) {
        if (!obj.key.endsWith('.json')) continue
        ids.push(obj.key.replace('videos/', '').replace('.json', ''))
    }
    return uniqueVideoIds(ids)
}

async function listAllVideoObjects(bucket: R2Bucket): Promise<R2Object[]> {
    const objects: R2Object[] = []
    let cursor: string | undefined
    do {
        const page = await bucket.list(cursor ? { prefix: 'videos/', cursor } : { prefix: 'videos/' })
        objects.push(...page.objects)
        cursor = page.truncated && page.cursor ? page.cursor : undefined
    } while (cursor)
    return objects
}

async function orderVideoIdsNewestFirst(bucket: R2Bucket, candidateIds: string[]): Promise<string[]> {
    const normalizedIds = uniqueVideoIds(candidateIds)
    if (normalizedIds.length <= 1) return normalizedIds

    try {
        const cacheObj = await bucket.get('_cache/gallery.json')
        if (!cacheObj) return normalizedIds

        const payload = await cacheObj.json() as { videos?: Array<{ id?: unknown; createdAt?: unknown }> }
        const cacheVideos = Array.isArray(payload?.videos) ? payload.videos : []
        const idSet = new Set(normalizedIds)
        const orderedFromCache: Array<{ id: string; createdAtMs: number; index: number }> = []

        for (let i = 0; i < cacheVideos.length; i += 1) {
            const row = cacheVideos[i]
            const id = String(row?.id || '').trim()
            if (!id || !idSet.has(id)) continue
            orderedFromCache.push({
                id,
                createdAtMs: parseVideoCreatedAtMs(row?.createdAt),
                index: i,
            })
        }

        orderedFromCache.sort((a, b) => {
            if (a.createdAtMs !== b.createdAtMs) return b.createdAtMs - a.createdAtMs
            return a.index - b.index
        })

        const seen = new Set<string>()
        const orderedIds: string[] = []
        for (const row of orderedFromCache) {
            if (seen.has(row.id)) continue
            seen.add(row.id)
            orderedIds.push(row.id)
        }
        for (const id of normalizedIds) {
            if (!seen.has(id)) orderedIds.push(id)
        }
        return orderedIds
    } catch (e) {
        console.log(`[VIDEO ORDER] failed to read gallery cache for newest-first: ${e instanceof Error ? e.message : String(e)}`)
        return normalizedIds
    }
}

function hasShopeeLinkInMeta(meta: Record<string, unknown>): boolean {
    return !!normalizeMetaShopeeLink(meta)
}

function hasLazadaLinkInMeta(meta: Record<string, unknown>): boolean {
    return !!normalizeMetaLazadaLink(meta)
}

function hasAffiliateLinkInMeta(meta: Record<string, unknown>): boolean {
    return hasShopeeLinkInMeta(meta) || hasLazadaLinkInMeta(meta)
}

function normalizeGallerySearchQuery(value: string | null | undefined): string {
    return String(value || '').trim().toLowerCase().replace(/\s+/g, ' ')
}

function normalizeGalleryVideoIdSearchToken(value: string | null | undefined): string {
    return String(value || '').trim().toLowerCase().replace(/\s+/g, '').replace(/o/g, '0')
}

function matchesGallerySearchQuery(video: Record<string, unknown>, query: string): boolean {
    const needle = normalizeGallerySearchQuery(query)
    if (!needle) return true
    const idNeedle = normalizeGalleryVideoIdSearchToken(query)

    const haystacks = [
        video.id,
        video.video_id,
        video.title,
        video.script,
        video.category,
        video.owner_email,
        video.namespace_id,
    ]

    if (haystacks.some((value) => normalizeGallerySearchQuery(String(value || '')).includes(needle))) {
        return true
    }

    if (!idNeedle) return false

    const idHaystacks = [video.id, video.video_id]
    return idHaystacks.some((value) => normalizeGalleryVideoIdSearchToken(String(value || '')).includes(idNeedle))
}

function parseNonNegativeInt(value: string | null | undefined, fallback: number): number {
    const parsed = Number.parseInt(String(value || '').trim(), 10)
    if (!Number.isFinite(parsed) || parsed < 0) return fallback
    return parsed
}

function sliceGalleryPage<T>(videos: T[], offset: number, limit: number): { videos: T[]; hasMore: boolean } {
    const safeOffset = Math.max(0, offset)
    const safeLimit = Math.max(1, limit)
    const pageVideos = videos.slice(safeOffset, safeOffset + safeLimit)
    return {
        videos: pageVideos,
        hasMore: safeOffset + pageVideos.length < videos.length,
    }
}

async function pickPostableVideoNewestFirst(
    bucket: R2Bucket,
    candidateIds: string[],
): Promise<{ id: string; meta: Record<string, unknown>; shopeeLink: string; sourceNamespaceId?: string } | null> {
    const orderedIds = await orderVideoIdsNewestFirst(bucket, candidateIds)
    if (orderedIds.length === 0) return null

    const cacheHasLink = new Map<string, boolean>()
    const cacheShopeeLink = new Map<string, string>()
    try {
        const cacheObj = await bucket.get('_cache/gallery.json')
        if (cacheObj) {
            const payload = await cacheObj.json() as { videos?: Array<Record<string, unknown>> }
            const rows = Array.isArray(payload?.videos) ? payload.videos : []
            for (const row of rows) {
                const id = String(row?.id || '').trim()
                if (!id) continue
                const shopeeFromCache = normalizeMetaShopeeLink(row) || ''
                cacheHasLink.set(id, !!shopeeFromCache)
                if (shopeeFromCache) {
                    cacheShopeeLink.set(id, shopeeFromCache)
                }
            }
        }
    } catch (e) {
        console.log(`[VIDEO PICK] failed to read gallery cache: ${e instanceof Error ? e.message : String(e)}`)
    }

    const strictCandidates: string[] = []
    const unknownCandidates: string[] = []
    for (const id of orderedIds) {
        if (cacheHasLink.has(id)) {
            if (cacheHasLink.get(id)) strictCandidates.push(id)
            continue
        }
        unknownCandidates.push(id)
    }

    const scanOrder = [...strictCandidates, ...unknownCandidates]
    for (const id of scanOrder) {
        const metaObj = await bucket.get(`videos/${id}.json`)
        if (!metaObj) continue
        const meta = await metaObj.json() as Record<string, unknown>
        const shopeeLink = normalizeMetaShopeeLink(meta) || cacheShopeeLink.get(id) || ''
        if (!shopeeLink) continue
        return { id, meta, shopeeLink }
    }

    return null
}

async function pickRandomPostableVideoFromNamespaceGallery(
    bucket: R2Bucket,
    candidateIds: string[],
    namespaceId: string,
): Promise<{ id: string; meta: Record<string, unknown>; shopeeLink: string; sourceNamespaceId: string } | null> {
    const normalizedNamespaceId = String(namespaceId || '').trim() || 'default'
    const allowedIds = new Set(uniqueVideoIds(candidateIds))
    if (allowedIds.size === 0) return null

    try {
        const cacheObj = await bucket.get('_cache/gallery.json')
        if (cacheObj) {
            const payload = await cacheObj.json() as { videos?: Array<Record<string, unknown>> }
            const rows = dedupeVideosById(Array.isArray(payload?.videos) ? payload.videos : [])
            const shuffled = shuffleInPlace(rows.filter((row) => {
                const id = String(row?.id || '').trim()
                return !!id && allowedIds.has(id) && !!normalizeMetaShopeeLink(row)
            }))
            for (const row of shuffled) {
                const id = String(row?.id || '').trim()
                const shopeeLink = normalizeMetaShopeeLink(row)
                if (!id || !shopeeLink) continue
                return {
                    id,
                    meta: row,
                    shopeeLink,
                    sourceNamespaceId: normalizedNamespaceId,
                }
            }
        }
    } catch (e) {
        console.log(`[VIDEO PICK] failed to read gallery cache for random pick: ${e instanceof Error ? e.message : String(e)}`)
    }

    const shuffledIds = shuffleInPlace([...allowedIds])
    for (const id of shuffledIds) {
        const metaObj = await bucket.get(`videos/${id}.json`)
        if (!metaObj) continue
        const meta = await metaObj.json() as Record<string, unknown>
        const shopeeLink = normalizeMetaShopeeLink(meta) || ''
        if (!shopeeLink) continue
        return {
            id,
            meta,
            shopeeLink,
            sourceNamespaceId: normalizedNamespaceId,
        }
    }

    return null
}

async function pickRandomGalleryVideoForPosting(params: {
    env: Env
    namespaceId: string
    bucket: R2Bucket
    candidateIds: string[]
    excludedVideoIds: Set<string>
}): Promise<{ id: string; meta: Record<string, unknown>; shopeeLink: string; sourceNamespaceId: string } | null> {
    const namespaceId = String(params.namespaceId || '').trim() || 'default'
    const candidateIds = uniqueVideoIds(params.candidateIds).filter((id) => !params.excludedVideoIds.has(id))
    if (candidateIds.length === 0) return null
    const allowedIds = new Set(candidateIds)

    const shortlinkEnabled = await isSystemGalleryEnabledForNamespace(params.env.DB, namespaceId)
    if (!shortlinkEnabled) {
        return null
    }

    const galleryVideos = await listNamespaceGalleryVideos(params.env, namespaceId)
    const candidates = galleryVideos.filter((video) => {
        const id = String(video?.id || '').trim()
        return !!id && allowedIds.has(id) && !params.excludedVideoIds.has(id)
    })
    if (candidates.length > 0) {
        shuffleInPlace(candidates)
        const picked = candidates[0] as Record<string, unknown>
        return {
            id: String(picked.id || '').trim(),
            meta: picked,
            shopeeLink: normalizeMetaShopeeLink(picked) || '',
            sourceNamespaceId: String((picked as any).sourceNamespaceId || (picked as any).source_namespace_id || namespaceId).trim() || namespaceId,
        }
    }

    return null
}

async function resolveGalleryVideoForRepost(params: {
    env: Env
    fallbackNamespaceId: string
    videoId: string
}): Promise<{ id: string; meta: Record<string, unknown>; shopeeLink: string; sourceNamespaceId: string } | null> {
    const videoId = String(params.videoId || '').trim()
    const fallbackNamespaceId = String(params.fallbackNamespaceId || '').trim() || 'default'
    if (!videoId) return null

    const shortlinkEnabled = await isSystemGalleryEnabledForNamespace(params.env.DB, fallbackNamespaceId)
    if (!shortlinkEnabled) {
        return null
    }

    const namespaceGalleryVideos = await listNamespaceGalleryVideos(params.env, fallbackNamespaceId)
    const namespaceHit = namespaceGalleryVideos.find((video) => String(video.id || '').trim() === videoId)
    if (namespaceHit) {
        return {
            id: videoId,
            meta: namespaceHit,
            shopeeLink: normalizeMetaShopeeLink(namespaceHit as Record<string, unknown>) || '',
            sourceNamespaceId: fallbackNamespaceId,
        }
    }

    await ensureGalleryIndexTable(params.env.DB)
    const galleryRow = await params.env.DB.prepare(
        `SELECT
            namespace_id,
            owner_email,
            script,
            title,
            category,
            duration,
            shopee_link,
            public_url,
            original_url,
            thumbnail_url,
            created_at,
            updated_at
         FROM gallery_index
         WHERE video_id = ?
         ORDER BY CASE WHEN namespace_id = ? THEN 0 ELSE 1 END,
                  COALESCE(updated_at, created_at) DESC,
                  namespace_id ASC
         LIMIT 1`
    ).bind(videoId, fallbackNamespaceId).first() as {
        namespace_id?: string
        owner_email?: string
        script?: string
        title?: string
        category?: string
        duration?: number
        shopee_link?: string
        public_url?: string
        original_url?: string
        thumbnail_url?: string
        created_at?: string
        updated_at?: string
    } | null

    const namespaceCandidates = uniqueVideoIds([
        String(galleryRow?.namespace_id || '').trim(),
        fallbackNamespaceId,
    ])

    for (const namespaceId of namespaceCandidates) {
        if (!namespaceId) continue
        const bucket = namespaceId === fallbackNamespaceId
            ? new BotBucket(params.env.BUCKET, fallbackNamespaceId) as unknown as R2Bucket
            : new BotBucket(params.env.BUCKET, namespaceId) as unknown as R2Bucket

        const metaObj = await bucket.get(`videos/${videoId}.json`)
        if (!metaObj && namespaceId !== String(galleryRow?.namespace_id || '').trim()) {
            continue
        }

        let meta: Record<string, unknown> = {
            id: videoId,
            namespace_id: namespaceId,
            owner_email: String(galleryRow?.owner_email || '').trim(),
            script: String(galleryRow?.script || '').trim(),
            title: String(galleryRow?.title || '').trim(),
            category: String(galleryRow?.category || '').trim(),
            duration: Number(galleryRow?.duration || 0),
            shopeeLink: String(galleryRow?.shopee_link || '').trim(),
            publicUrl: String(galleryRow?.public_url || '').trim(),
            originalUrl: String(galleryRow?.original_url || '').trim(),
            thumbnailUrl: String(galleryRow?.thumbnail_url || '').trim(),
            createdAt: String(galleryRow?.created_at || '').trim(),
            updatedAt: String(galleryRow?.updated_at || '').trim(),
        }
        if (metaObj) {
            try {
                meta = {
                    ...meta,
                    ...(await metaObj.json() as Record<string, unknown>),
                }
            } catch {
                // Keep index-derived metadata as fallback.
            }
        }

        const shopeeLink = normalizeMetaShopeeLink(meta) || String(galleryRow?.shopee_link || '').trim()
        return {
            id: videoId,
            meta,
            shopeeLink,
            sourceNamespaceId: namespaceId,
        }
    }

    return null
}

function getVideoPublicUrlForNamespace(r2BaseUrl: string, namespaceId: string, videoId: string): string {
    return String(namespaceId || '').trim() === 'default'
        ? `${r2BaseUrl}/videos/${videoId}.mp4`
        : `${r2BaseUrl}/${namespaceId}/videos/${videoId}.mp4`
}

function getVideoThumbnailUrlForNamespace(r2BaseUrl: string, namespaceId: string, videoId: string): string {
    return String(namespaceId || '').trim() === 'default'
        ? `${r2BaseUrl}/videos/${videoId}_thumb.webp`
        : `${r2BaseUrl}/${namespaceId}/videos/${videoId}_thumb.webp`
}

function getVideoOriginalThumbnailUrlForNamespace(r2BaseUrl: string, namespaceId: string, videoId: string): string {
    return String(namespaceId || '').trim() === 'default'
        ? `${r2BaseUrl}/videos/${videoId}_original_thumb.webp`
        : `${r2BaseUrl}/${namespaceId}/videos/${videoId}_original_thumb.webp`
}

type GalleryAssetVariant = 'public' | 'original' | 'thumb' | 'original-thumb'

function buildNamespaceObjectUrl(r2BaseUrl: string, namespaceId: string, objectKey: string): string {
    const base = String(r2BaseUrl || '').trim().replace(/\/+$/, '')
    const normalizedKey = String(objectKey || '').trim().replace(/^\/+/, '')
    const normalizedNamespaceId = String(namespaceId || '').trim()
    if (!base || !normalizedKey) return ''
    return normalizedNamespaceId === 'default'
        ? `${base}/${normalizedKey}`
        : `${base}/${normalizedNamespaceId}/${normalizedKey}`
}

function getOriginalVideoAssetKeys(videoId: string): string[] {
    const normalizedId = String(videoId || '').trim()
    if (!normalizedId) return []
    return [
        `videos/${normalizedId}_original.mp4`,
        `videos/${normalizedId}_line_original.mp4`,
    ]
}

function getProcessedThumbnailAssetKey(videoId: string): string {
    return `videos/${String(videoId || '').trim()}_thumb.webp`
}

function getOriginalThumbnailAssetKey(videoId: string): string {
    return `videos/${String(videoId || '').trim()}_original_thumb.webp`
}

function isNamespaceAssetUrlForNamespace(url: unknown, namespaceId: string): boolean {
    const normalizedUrl = String(url || '').trim()
    const normalizedNamespaceId = String(namespaceId || '').trim()
    if (!normalizedUrl || !normalizedNamespaceId) return false
    return normalizedUrl.includes(`/${normalizedNamespaceId}/videos/`)
}

async function clearNamespaceProcessedArtifacts(bucket: R2Bucket, videoId: string): Promise<void> {
    const normalizedVideoId = String(videoId || '').trim()
    if (!normalizedVideoId) return
    await Promise.all([
        bucket.delete(`videos/${normalizedVideoId}.json`).catch(() => { }),
        bucket.delete(`videos/${normalizedVideoId}.mp4`).catch(() => { }),
        bucket.delete(getProcessedThumbnailAssetKey(normalizedVideoId)).catch(() => { }),
        bucket.delete(`_processing/${normalizedVideoId}.json`).catch(() => { }),
        bucket.delete(`_queue/${normalizedVideoId}.json`).catch(() => { }),
    ])
}

function isImportedVideoMetaPointingAtSourceNamespace(params: {
    meta: Record<string, unknown>
    targetNamespaceId: string
    sourceNamespaceId: string
}): boolean {
    const targetNamespaceId = String(params.targetNamespaceId || '').trim()
    const sourceNamespaceId = String(params.sourceNamespaceId || '').trim()
    if (!targetNamespaceId || !sourceNamespaceId || targetNamespaceId === sourceNamespaceId) return false

    const meta = params.meta || {}
    const importedFrom = String(meta.importedFrom || meta.sourceNamespaceId || meta.source_namespace_id || '').trim()
    const originalUrl = String(meta.originalUrl || meta.original_url || '').trim()
    const publicUrl = String(meta.publicUrl || meta.public_url || '').trim()
    const thumbnailUrl = String(meta.thumbnailUrl || meta.thumbnail_url || '').trim()

    const pointsToSource =
        isNamespaceAssetUrlForNamespace(originalUrl, sourceNamespaceId)
        || isNamespaceAssetUrlForNamespace(publicUrl, sourceNamespaceId)
        || isNamespaceAssetUrlForNamespace(thumbnailUrl, sourceNamespaceId)
    const pointsToTarget =
        isNamespaceAssetUrlForNamespace(originalUrl, targetNamespaceId)
        || isNamespaceAssetUrlForNamespace(publicUrl, targetNamespaceId)
        || isNamespaceAssetUrlForNamespace(thumbnailUrl, targetNamespaceId)

    return !!(
        (importedFrom && importedFrom === sourceNamespaceId && !pointsToTarget)
        || pointsToSource
    )
}

function getGalleryAssetKeys(videoId: string, variant: GalleryAssetVariant): string[] {
    const normalizedId = String(videoId || '').trim()
    if (!normalizedId) return []
    switch (variant) {
        case 'original-thumb':
            return [getOriginalThumbnailAssetKey(normalizedId)]
        case 'thumb':
            return [getProcessedThumbnailAssetKey(normalizedId)]
        case 'original':
            return getOriginalVideoAssetKeys(normalizedId)
        case 'public':
        default:
            return [`videos/${normalizedId}.mp4`]
    }
}

function getGalleryAssetKey(videoId: string, variant: GalleryAssetVariant): string {
    return getGalleryAssetKeys(videoId, variant)[0] || ''
}

async function resolveGalleryAssetKey(bucket: R2Bucket, videoId: string, variant: GalleryAssetVariant): Promise<string> {
    const candidates = getGalleryAssetKeys(videoId, variant)
    if (candidates.length <= 1) return candidates[0] || ''

    for (const candidate of candidates) {
        const head = await bucket.head(candidate).catch(() => null)
        if (head) return candidate
    }
    return candidates[0] || ''
}

function getGalleryAssetFallbackContentType(variant: GalleryAssetVariant): string {
    return variant === 'thumb' || variant === 'original-thumb' ? 'image/webp' : 'video/mp4'
}

function buildWorkerGalleryAssetUrl(workerUrl: string, namespaceId: string, videoId: string, variant: GalleryAssetVariant): string {
    const normalizedWorkerUrl = String(workerUrl || '').trim().replace(/\/+$/, '')
    const normalizedNamespaceId = String(namespaceId || '').trim()
    const normalizedVideoId = String(videoId || '').trim()
    if (!normalizedWorkerUrl || !normalizedNamespaceId || !normalizedVideoId) return ''
    try {
        const url = new URL(`${normalizedWorkerUrl}/api/gallery/${encodeURIComponent(normalizedVideoId)}/asset/${variant}`)
        url.searchParams.set('namespace_id', normalizedNamespaceId)
        return url.toString()
    } catch {
        return `${normalizedWorkerUrl}/api/gallery/${encodeURIComponent(normalizedVideoId)}/asset/${variant}?namespace_id=${encodeURIComponent(normalizedNamespaceId)}`
    }
}

function buildWorkerGalleryFrameUrl(
    workerUrl: string,
    namespaceId: string,
    videoId: string,
    options?: {
        seed?: string
        format?: 'webp' | 'jpg'
        width?: number
        height?: number
        timeSeconds?: number
        coverText?: string
        coverTextYPercent?: number
        coverTemplateId?: string
        coverTextStyle?: Partial<CoverTextStyleSettings> | null
    },
): string {
    const normalizedWorkerUrl = String(workerUrl || '').trim().replace(/\/+$/, '')
    const normalizedNamespaceId = String(namespaceId || '').trim()
    const normalizedVideoId = String(videoId || '').trim()
    if (!normalizedWorkerUrl || !normalizedNamespaceId || !normalizedVideoId) return ''

    const normalizedSeed = String(options?.seed || '').trim()
    const requestedFormat = options?.format === 'jpg' ? 'jpg' : 'webp'
    const width = Number.isFinite(options?.width) ? Math.max(120, Math.min(1440, Math.round(Number(options?.width)))) : undefined
    const height = Number.isFinite(options?.height) ? Math.max(160, Math.min(2560, Math.round(Number(options?.height)))) : undefined
    const timeSeconds = Number.isFinite(options?.timeSeconds) ? Math.max(0, Number(options?.timeSeconds)) : undefined
    const coverText = normalizeLineCoverText(options?.coverText)
    const coverTextYPercent = Number.isFinite(options?.coverTextYPercent)
        ? Math.max(10, Math.min(90, Math.round(Number(options?.coverTextYPercent))))
        : undefined
    const coverTemplateId = normalizeCoverTemplateId(String(options?.coverTemplateId || ''))
    const coverTextStyle = normalizeCoverTextStyle(options?.coverTextStyle, coverTemplateId)

    try {
        const url = new URL(`${normalizedWorkerUrl}/api/gallery/${encodeURIComponent(normalizedVideoId)}/frame`)
        url.searchParams.set('namespace_id', normalizedNamespaceId)
        if (normalizedSeed) url.searchParams.set('seed', normalizedSeed)
        if (requestedFormat) url.searchParams.set('format', requestedFormat)
        if (width) url.searchParams.set('w', String(width))
        if (height) url.searchParams.set('h', String(height))
        if (Number.isFinite(timeSeconds)) url.searchParams.set('t', String(timeSeconds))
        if (coverText) url.searchParams.set('ct', coverText)
        if (Number.isFinite(coverTextYPercent)) url.searchParams.set('cy', String(coverTextYPercent))
        if (coverText) {
            url.searchParams.set('tid', coverTemplateId)
            url.searchParams.set('tf', coverTextStyle.fontId)
            url.searchParams.set('tc', coverTextStyle.textColor)
            url.searchParams.set('tc2', coverTextStyle.secondaryTextColor)
            url.searchParams.set('bc', coverTextStyle.backgroundColor)
            url.searchParams.set('bo', String(coverTextStyle.backgroundOpacity))
            url.searchParams.set('ts', String(coverTextStyle.sizeScale))
            url.searchParams.set('af', coverTextStyle.autoFit ? '1' : '0')
            url.searchParams.set('om', coverTextStyle.mode)
            url.searchParams.set('oc', coverTextStyle.outlineColor)
            url.searchParams.set('ow', String(coverTextStyle.outlineWidth))
        }
        return url.toString()
    } catch {
        const params = new URLSearchParams()
        params.set('namespace_id', normalizedNamespaceId)
        if (normalizedSeed) params.set('seed', normalizedSeed)
        if (requestedFormat) params.set('format', requestedFormat)
        if (width) params.set('w', String(width))
        if (height) params.set('h', String(height))
        if (Number.isFinite(timeSeconds)) params.set('t', String(timeSeconds))
        if (coverText) params.set('ct', coverText)
        if (Number.isFinite(coverTextYPercent)) params.set('cy', String(coverTextYPercent))
        if (coverText) {
            params.set('tid', coverTemplateId)
            params.set('tf', coverTextStyle.fontId)
            params.set('tc', coverTextStyle.textColor)
            params.set('tc2', coverTextStyle.secondaryTextColor)
            params.set('bc', coverTextStyle.backgroundColor)
            params.set('bo', String(coverTextStyle.backgroundOpacity))
            params.set('ts', String(coverTextStyle.sizeScale))
            params.set('af', coverTextStyle.autoFit ? '1' : '0')
            params.set('om', coverTextStyle.mode)
            params.set('oc', coverTextStyle.outlineColor)
            params.set('ow', String(coverTextStyle.outlineWidth))
        }
        return `${normalizedWorkerUrl}/api/gallery/${encodeURIComponent(normalizedVideoId)}/frame?${params.toString()}`
    }
}

function resolvePostingVideoDownloadUrl(
    env: Env,
    namespaceId: string,
    videoId: string,
    rawPublicUrl = '',
): string {
    const normalizedNamespaceId = String(namespaceId || '').trim()
    const normalizedVideoId = String(videoId || '').trim()
    const workerAssetUrl = buildWorkerGalleryAssetUrl(
        String(env.WORKER_URL || '').trim(),
        normalizedNamespaceId,
        normalizedVideoId,
        'public',
    )
    if (workerAssetUrl) return workerAssetUrl

    const publicUrl = String(rawPublicUrl || '').trim()
    if (publicUrl && publicUrl.includes(`/${normalizedNamespaceId}/videos/`)) {
        return publicUrl
    }

    return getVideoPublicUrlForNamespace(env.R2_PUBLIC_URL, normalizedNamespaceId, normalizedVideoId)
}

function parseSingleRangeHeader(rangeHeader: string, size: number): { offset: number; length: number; end: number } | 'unsatisfiable' | null {
    const normalized = String(rangeHeader || '').trim()
    if (!normalized) return null

    const match = normalized.match(/^bytes=(\d*)-(\d*)$/i)
    if (!match) return null

    const [, startRaw, endRaw] = match
    if (!startRaw && !endRaw) return 'unsatisfiable'

    if (!startRaw) {
        const suffixLength = Number(endRaw)
        if (!Number.isFinite(suffixLength) || suffixLength <= 0) return 'unsatisfiable'
        const length = Math.min(size, suffixLength)
        const offset = Math.max(0, size - length)
        return { offset, length, end: size - 1 }
    }

    const start = Number(startRaw)
    if (!Number.isFinite(start) || start < 0 || start >= size) return 'unsatisfiable'

    const requestedEnd = endRaw ? Number(endRaw) : size - 1
    if (!Number.isFinite(requestedEnd) || requestedEnd < start) return 'unsatisfiable'

    const end = Math.min(size - 1, requestedEnd)
    return { offset: start, length: end - start + 1, end }
}

async function buildGalleryAssetResponse(
    bucket: R2Bucket,
    key: string,
    variant: GalleryAssetVariant,
    rangeHeader?: string | null,
): Promise<Response> {
    const head = await bucket.head(key)
    if (!head) return new Response('Not found', { status: 404 })

    const headers = new Headers({
        'Accept-Ranges': 'bytes',
        'Cache-Control': 'public, max-age=31536000, immutable',
        'Content-Type': head.httpMetadata?.contentType || getGalleryAssetFallbackContentType(variant),
        'Access-Control-Allow-Origin': '*',
    })
    if (head.httpEtag) headers.set('ETag', head.httpEtag)

    const range = parseSingleRangeHeader(String(rangeHeader || ''), head.size)
    if (range === 'unsatisfiable') {
        headers.set('Content-Range', `bytes */${head.size}`)
        return new Response(null, { status: 416, headers })
    }

    if (range) {
        const obj = await bucket.get(key, { range: { offset: range.offset, length: range.length } })
        if (!obj) return new Response('Not found', { status: 404 })
        headers.set('Content-Length', String(range.length))
        headers.set('Content-Range', `bytes ${range.offset}-${range.end}/${head.size}`)
        return new Response(obj.body, { status: 206, headers })
    }

    const obj = await bucket.get(key)
    if (!obj) return new Response('Not found', { status: 404 })
    headers.set('Content-Length', String(head.size))
    return new Response(obj.body, { status: 200, headers })
}

