// ==================== AUTH ====================

app.post('/api/auth/login', async (c) => {
    const { email, tg_id, bot_id } = await c.req.json()
    const botScope = String(bot_id || '').trim()

    // Auto-login by tg_id (Telegram WebApp init)
    if (tg_id && !email) {
        if (botScope) {
            const scoped = await getTelegramBotSession(c.env.DB, String(tg_id), botScope)
            if (scoped?.session_token) return c.json({ session_token: scoped.session_token })
            const legacyUser = await c.env.DB.prepare(
                'SELECT session_token, namespace_id FROM users WHERE telegram_id = ?'
            ).bind(String(tg_id)).first() as { session_token?: string; namespace_id?: string } | null
            const legacyNamespaceId = String(legacyUser?.namespace_id || '').trim()
            if (legacyUser?.session_token && legacyNamespaceId === botScope) {
                return c.json({ session_token: String(legacyUser.session_token || '').trim() })
            }
            const existingSessionToken = String(c.req.header('x-auth-token') || '').trim()
            const bound = await bindTelegramToExistingSession(c.env.DB, existingSessionToken, String(tg_id), botScope)
            if (bound?.session_token) {
                return c.json({ session_token: bound.session_token, rebound: true })
            }
            const provisioned = await provisionTelegramOwnerSession(c.env.DB, String(tg_id), botScope)
            if (provisioned?.session_token) {
                return c.json({ session_token: provisioned.session_token, is_owner: true, auto_provisioned: true })
            }
            return c.json({ error: 'Unauthorized' }, 401)
        }
        const user = await c.env.DB.prepare(
            'SELECT session_token FROM users WHERE telegram_id = ?'
        ).bind(String(tg_id)).first() as any
        if (user?.session_token) return c.json({ session_token: user.session_token })
        return c.json({ error: 'Not registered' }, 401)
    }

    // Email login
    if (!email || !email.includes('@')) return c.json({ error: 'Invalid email' }, 400)
    const emailLower = email.toLowerCase()

    // Check if team member first, otherwise treat as namespace owner
    const teamMember = await c.env.DB.prepare('SELECT owner_namespace_id FROM team_members WHERE lower(trim(email)) = ?').bind(emailLower).first() as any
    const isOwner = !teamMember

    const sessionToken = 'sess_' + crypto.randomUUID().replace(/-/g, '')

    // Resolve canonical namespace:
    // - Team member: always use owner namespace
    // - Owner (anyone not a team member): ensure namespace via email_namespaces
    let namespaceId: string | null = null

    if (teamMember?.owner_namespace_id) {
        namespaceId = String(teamMember.owner_namespace_id)
    } else {
        // Every non-team-member is a namespace owner - ensure they have a proper namespace
        namespaceId = await ensureOwnerWorkspaceUsesEmailNamespace(c.env.DB, emailLower, { preferExistingNamespace: true })
    }

    // Persist canonical email mapping for all namespace owners
    if (isOwner && namespaceId) {
        try {
            await upsertOwnerNamespaceMapping(c.env.DB, emailLower, namespaceId)
        } catch (e) {
            console.log(`[AUTH] email_namespaces insert skipped: ${String(e)}`)
        }
    }

    // Normalize all rows for this email to avoid workspace drift
    await c.env.DB.prepare('UPDATE users SET namespace_id = ? WHERE email = ?')
        .bind(namespaceId, emailLower).run()

    const bindTgId = tg_id ? String(tg_id).trim() : '';

    if (bindTgId && botScope) {
        await upsertUserSessionByTelegram(c.env.DB, bindTgId, emailLower, namespaceId, sessionToken)
        await upsertTelegramBotSession(c.env.DB, bindTgId, botScope, emailLower, namespaceId, sessionToken)
    } else if (bindTgId) {
        await upsertUserSessionByTelegram(c.env.DB, bindTgId, emailLower, namespaceId, sessionToken)
    } else {
        // Reuse the bot-owner row when present so one owner email maps to one account row.
        const existingEmailUser = await c.env.DB.prepare(
            `SELECT u.telegram_id
             FROM users u
             LEFT JOIN channels ch
               ON CAST(u.telegram_id AS TEXT) = CAST(ch.owner_telegram_id AS TEXT)
             WHERE lower(trim(u.email)) = ?
             ORDER BY
               CASE WHEN ch.owner_telegram_id IS NOT NULL THEN 0 ELSE 1 END ASC,
               datetime(u.created_at) ASC,
               u.telegram_id ASC
             LIMIT 1`
        ).bind(emailLower).first() as { telegram_id?: number } | null

        if (existingEmailUser?.telegram_id != null) {
            await c.env.DB.prepare(
                'UPDATE users SET email = ?, namespace_id = ?, session_token = ? WHERE telegram_id = ?'
            ).bind(emailLower, namespaceId, sessionToken, Number(existingEmailUser.telegram_id)).run()
            await c.env.DB.prepare(
                `UPDATE telegram_bot_sessions
                 SET email = ?, namespace_id = ?, session_token = ?, updated_at = datetime('now')
                 WHERE telegram_id = ?`
            ).bind(emailLower, namespaceId, sessionToken, String(existingEmailUser.telegram_id)).run().catch(() => { })

            if (isOwner) {
                await c.env.DB.prepare(
                    'DELETE FROM users WHERE lower(trim(email)) = ? AND telegram_id <> ?'
                ).bind(emailLower, Number(existingEmailUser.telegram_id)).run()
            }
        } else {
            await c.env.DB.prepare('INSERT INTO users (email, namespace_id, session_token) VALUES (?, ?, ?)')
                .bind(emailLower, namespaceId, sessionToken).run()
        }
    }

    const sysAdmin = isOwner ? await isSystemAdmin(c.env.DB, emailLower) : false
    return c.json({ session_token: sessionToken, is_owner: isOwner, is_system_admin: sysAdmin })
})

app.post('/api/auth/logout', async (c) => {
    const token = getSessionTokenFromRequest(c)
    if (!token.startsWith('sess_')) return c.json({ error: 'Unauthorized' }, 401)
    await c.env.DB.prepare("UPDATE users SET session_token = '' WHERE session_token = ?").bind(token).run()
    await clearTelegramBotSessionByToken(c.env.DB, token)
    return c.json({ ok: true }, 200, {
        'Set-Cookie': buildClearedSessionCookie(),
        'Cache-Control': 'no-store',
    })
})

app.post('/api/auth/resolve-email', async (c) => {
    const body = await c.req.json().catch(() => ({})) as { email?: string }
    const email = String(body.email || '').trim().toLowerCase()
    if (!email) return c.json({ error: 'email_required' }, 400)

    // Check if team member first
    const team = await c.env.DB.prepare(
        'SELECT owner_namespace_id FROM team_members WHERE lower(trim(email)) = ? LIMIT 1'
    ).bind(email).first() as { owner_namespace_id?: string } | null

    if (team?.owner_namespace_id) {
        // Team member: resolve via owner namespace
        const teamRows = await c.env.DB.prepare(
            'SELECT owner_namespace_id FROM team_members WHERE lower(trim(email)) = ?'
        ).bind(email).all() as { results: Array<{ owner_namespace_id: string }> }
        const teamNamespaces = Array.from(new Set(
            (teamRows.results || []).map(r => String(r.owner_namespace_id || '').trim()).filter(Boolean)
        ))
        return c.json({
            success: true,
            namespace_id: teamNamespaces[0],
            namespaces: teamNamespaces,
            is_owner: false,
            is_team_member: true,
        })
    }

    // Namespace owner (anyone not a team member)
    const ownerNamespace = await ensureOwnerWorkspaceUsesEmailNamespace(c.env.DB, email, { preferExistingNamespace: true })

    await c.env.DB.prepare('UPDATE users SET namespace_id = ? WHERE email = ?')
        .bind(ownerNamespace, email).run()

    const existingOwnerUser = await c.env.DB.prepare(
        'SELECT 1 AS ok FROM users WHERE lower(trim(email)) = ? LIMIT 1'
    ).bind(email).first() as { ok?: number } | null

    if (!existingOwnerUser?.ok) {
        await c.env.DB.prepare(
            "INSERT INTO users (email, namespace_id, session_token) VALUES (?, ?, '')"
        ).bind(email, ownerNamespace).run()
    }

    return c.json({
        success: true,
        namespace_id: ownerNamespace,
        namespaces: [ownerNamespace],
        is_owner: true,
        is_team_member: false,
    })
})

