// Refresh gallery cache for a specific video (called by container after pipeline completes)
app.post('/api/gallery/refresh/:id', async (c) => {
    try {
        const videoId = String(c.req.param('id') || '').trim()
        const namespaceId = String(c.get('botId') || '').trim()
        const linkContextObj = await c.get('bucket').get(`_link_context/${videoId}.json`)
        const linkContext = linkContextObj
            ? await linkContextObj.json() as {
                chatId?: number
                shopeeLink?: string
                lazadaLink?: string
                shopeeOriginalLink?: string
                lazadaOriginalLink?: string
                manualCaption?: string
                captionProvidedAt?: string
            }
            : null

        const refreshCompletedAt = new Date().toISOString()

        if (videoId && linkContext) {
            const metaObj = await c.get('bucket').get(`videos/${videoId}.json`)
            if (metaObj) {
                const meta = await metaObj.json() as Record<string, unknown>
                const shopeeLink = String(linkContext.shopeeLink || '').trim()
                const lazadaLink = String(linkContext.lazadaLink || '').trim()
                const shopeeOriginalLink = pickFirstShopeeUrl(String(linkContext.shopeeOriginalLink || shopeeLink || '')) || ''
                const lazadaOriginalLink = pickFirstLazadaUrl(String(linkContext.lazadaOriginalLink || lazadaLink || '')) || ''
                const manualCaption = normalizeManualCaption(linkContext.manualCaption)
                let changed = false
                const nextStateFields: Partial<NamespaceVideoStateRow> = {}
                if (shopeeLink && !normalizeMetaShopeeLink(meta)) {
                    meta.shopeeLink = shopeeLink
                    meta.shopeeOriginalLink = getVideoSourceShopeeLink(meta) || shopeeOriginalLink || shopeeLink
                    if (!String(meta.linkSubmittedAt || '').trim()) {
                        meta.linkSubmittedAt = new Date().toISOString()
                    }
                    nextStateFields.shopee_link = shopeeLink
                    nextStateFields.shopee_original_link = String(meta.shopeeOriginalLink || '').trim()
                    changed = true
                }
                if (lazadaLink && !normalizeMetaLazadaLink(meta)) {
                    meta.lazadaLink = lazadaLink
                    meta.lazadaOriginalLink = getVideoSourceLazadaLink(meta) || lazadaOriginalLink || lazadaLink
                    nextStateFields.lazada_link = lazadaLink
                    nextStateFields.lazada_original_link = String(meta.lazadaOriginalLink || '').trim()
                    changed = true
                }
                if (manualCaption && normalizeManualCaption(meta.manualCaption || '') !== manualCaption) {
                    meta.manualCaption = manualCaption
                    meta.captionSource = 'manual'
                    meta.captionProvidedAt = String(linkContext.captionProvidedAt || '').trim() || new Date().toISOString()
                    changed = true
                }
                if (changed) {
                    meta.id = String(meta.id || videoId).trim() || videoId
                    meta.namespace_id = String(meta.namespace_id || namespaceId).trim() || namespaceId
                    meta.processedAt = String(meta.processedAt || refreshCompletedAt).trim() || refreshCompletedAt
                    meta.updatedAt = refreshCompletedAt
                    await c.get('bucket').put(`videos/${videoId}.json`, JSON.stringify(meta, null, 2), {
                        httpMetadata: { contentType: 'application/json' },
                    })
                    await upsertNamespaceVideoState(c.env.DB, namespaceId, videoId, nextStateFields)
                }
            }
        }

        if (videoId) {
            const metaObj = await c.get('bucket').get(`videos/${videoId}.json`).catch(() => null)
            if (metaObj) {
                const meta = await metaObj.json().catch(() => null) as Record<string, unknown> | null
                if (meta) {
                    meta.id = String(meta.id || videoId).trim() || videoId
                    meta.namespace_id = String(meta.namespace_id || namespaceId).trim() || namespaceId
                    meta.processedAt = String(meta.processedAt || refreshCompletedAt).trim() || refreshCompletedAt
                    meta.updatedAt = refreshCompletedAt
                    await c.get('bucket').put(`videos/${videoId}.json`, JSON.stringify(meta, null, 2), {
                        httpMetadata: { contentType: 'application/json' },
                    })
                }
            }

            const inboxRecord = await getInboxVideoRecord(c.get('bucket'), videoId).catch(() => null)
            if (inboxRecord) {
                await putInboxVideoRecord(c.get('bucket'), {
                    ...inboxRecord,
                    processedAt: refreshCompletedAt,
                    updatedAt: refreshCompletedAt,
                }).catch(() => { })
            }
        }

        if (videoId) {
            await syncOriginalThumbnailToProcessedThumbnail({
                env: c.env,
                bucket: c.get('bucket'),
                namespaceId,
                videoId,
            }).catch(() => ({ synced: false, thumbnailUrl: '' }))
        }

        await updateGalleryCache(c.get('bucket'), videoId)
        await syncGalleryIndexEntry(c.env, namespaceId, videoId).catch((error) => {
            console.log(`[GALLERY-REFRESH] sync gallery index failed video=${videoId}: ${error instanceof Error ? error.message : String(error)}`)
        })
        await c.env.BUCKET.delete('_admin_cache/all_gallery_videos.json').catch(() => { })
        await c.env.BUCKET.delete('_admin_cache/all_gallery_owner_videos.json').catch(() => { })

        if (linkContext && Number(linkContext.chatId || 0) > 0) {
            let botToken = c.env.TELEGRAM_BOT_TOKEN
            try {
                const ch = await c.env.DB.prepare('SELECT bot_token FROM channels WHERE bot_id = ?').bind(namespaceId).first() as { bot_token?: string } | null
                if (String(ch?.bot_token || '').trim()) {
                    botToken = String(ch?.bot_token || '').trim()
                }
            } catch {
                // fall back to default token
            }
            const completionUrl = buildScopedGalleryWebAppUrl(
                getAppWebBaseUrl(c.env),
                namespaceId,
                'lazada',
                videoId,
            )
            await sendTelegram(botToken, 'sendMessage', {
                chat_id: Number(linkContext.chatId || 0),
                text: `✅ ประมวลผลเสร็จแล้ว\nVideo ID: ${videoId}`,
                reply_markup: {
                    inline_keyboard: [[{ text: '🧡 เปิด Gallery Lazada', web_app: { url: completionUrl } }]],
                },
            }).catch(() => null)
        }
        await c.get('bucket').delete(`_link_context/${videoId}.json`).catch(() => { })

        await c.get('bucket').delete(`_processing/${videoId}.json`).catch(() => { })

        // เช็คคิว → ถ้ามีงานรอ ให้เริ่มทำอันถัดไป
        c.executionCtx.waitUntil(processNextInQueue(c.env, c.get('botId')))

        return c.json({ ok: true })
    } catch (e) {
        return c.json({ error: String(e) }, 500)
    }
})

