async function ensureNamespaceSettingsTable(db: D1Database) {
    await db.prepare(
        `CREATE TABLE IF NOT EXISTS namespace_settings (
            namespace_id TEXT NOT NULL,
            key TEXT NOT NULL,
            value TEXT NOT NULL,
            created_at TEXT DEFAULT (datetime('now')),
            updated_at TEXT DEFAULT (datetime('now')),
            PRIMARY KEY (namespace_id, key)
        )`
    ).run()
}

function parseSelectorList(raw: string, fallback: string): string[] {
    const source = String(raw || '').trim() || fallback
    const out: string[] = []
    const seen = new Set<string>()
    for (const part of source.split(',')) {
        const selector = String(part || '').trim()
        if (!selector) continue
        const key = selector.toLowerCase()
        if (seen.has(key)) continue
        seen.add(key)
        out.push(selector)
    }
    return out
}

async function getNamespacePagesSyncConfig(db: D1Database, namespaceId: string): Promise<NamespacePagesSyncConfig> {
    await ensureNamespaceSettingsTable(db)
    const { results } = await db.prepare(
        `SELECT key, value
         FROM namespace_settings
         WHERE namespace_id = ?
           AND key IN (?, ?, ?)`
    ).bind(
        namespaceId,
        NS_SETTING_PAGES_SYNC_ENABLED,
        NS_SETTING_PAGES_SYNC_POST_SELECTORS,
        NS_SETTING_PAGES_SYNC_COMMENT_SELECTORS,
    ).all() as { results?: Array<{ key?: string; value?: string }> }

    const valueMap = new Map<string, string>()
    for (const row of results || []) {
        const key = String(row?.key || '').trim()
        if (!key) continue
        valueMap.set(key, String(row?.value || '').trim())
    }

    const hasExplicitEnabled = valueMap.has(NS_SETTING_PAGES_SYNC_ENABLED)
    const enabledRaw = String(valueMap.get(NS_SETTING_PAGES_SYNC_ENABLED) || '').trim().toLowerCase()
    let enabled = !(enabledRaw === '0' || enabledRaw === 'false' || enabledRaw === 'off' || enabledRaw === 'no')

    const postSelectors = parseSelectorList(
        String(valueMap.get(NS_SETTING_PAGES_SYNC_POST_SELECTORS) || ''),
        DEFAULT_PAGES_SYNC_POST_SELECTORS,
    )
    const commentSelectors = parseSelectorList(
        String(valueMap.get(NS_SETTING_PAGES_SYNC_COMMENT_SELECTORS) || ''),
        DEFAULT_PAGES_SYNC_COMMENT_SELECTORS,
    )

    return { enabled, postSelectors, commentSelectors }
}

async function getNamespaceSettingMs(db: D1Database, namespaceId: string, key: string): Promise<number> {
    await ensureNamespaceSettingsTable(db)
    const row = await db.prepare(
        'SELECT value FROM namespace_settings WHERE namespace_id = ? AND key = ?'
    ).bind(namespaceId, key).first() as { value?: string } | null
    const parsed = Number(String(row?.value || '').trim())
    return Number.isFinite(parsed) ? parsed : 0
}

async function setNamespaceSettingMs(db: D1Database, namespaceId: string, key: string, valueMs: number): Promise<void> {
    await ensureNamespaceSettingsTable(db)
    const value = String(Math.max(0, Math.floor(Number(valueMs) || 0)))
    await db.prepare(
        `INSERT INTO namespace_settings (namespace_id, key, value, created_at, updated_at)
         VALUES (?, ?, ?, datetime('now'), datetime('now'))
         ON CONFLICT(namespace_id, key) DO UPDATE SET
           value = excluded.value,
           updated_at = datetime('now')`
    ).bind(namespaceId, key, value).run()
}

function maskApiKeyForDisplay(rawValue: string): string {
    const value = String(rawValue || '').trim()
    if (!value) return ''
    if (value.length <= 8) {
        const left = value.slice(0, 2)
        const right = value.slice(-2)
        return `${left}...${right}`
    }
    return `${value.slice(0, 4)}...${value.slice(-4)}`
}

async function getNamespaceGeminiApiKeyEntry(db: D1Database, namespaceId: string): Promise<{ key: string; updatedAt: string | null }> {
    await ensureNamespaceSettingsTable(db)
    const row = await db.prepare(
        'SELECT value, updated_at FROM namespace_settings WHERE namespace_id = ? AND key = ?'
    ).bind(namespaceId, NS_SETTING_GEMINI_API_KEY).first() as { value?: string; updated_at?: string } | null
    return {
        key: String(row?.value || '').trim(),
        updatedAt: String(row?.updated_at || '').trim() || null,
    }
}

function normalizeGeminiApiKeyList(rawKeys: unknown): string[] {
    const source = Array.isArray(rawKeys)
        ? rawKeys
        : typeof rawKeys === 'string'
            ? [rawKeys]
            : []
    const out: string[] = []
    const seen = new Set<string>()
    for (const raw of source) {
        const key = String(raw || '').trim().slice(0, MAX_GEMINI_API_KEY_CHARS)
        if (!key) continue
        if (seen.has(key)) continue
        seen.add(key)
        out.push(key)
        if (out.length >= MAX_GEMINI_API_KEY_SLOTS) break
    }
    return out
}

async function getLegacySystemGeminiApiKeys(db: D1Database): Promise<{ keys: string[]; updatedAt: string | null }> {
    await ensureNamespaceSettingsTable(db)
    const rows = await db.prepare(
        `SELECT ns.value, ns.updated_at
         FROM namespace_settings ns
         INNER JOIN users u
           ON u.namespace_id = ns.namespace_id
         INNER JOIN system_admins sa
           ON lower(trim(sa.email)) = lower(trim(u.email))
         WHERE ns.key = ?
           AND trim(coalesce(ns.value, '')) <> ''
         ORDER BY datetime(ns.updated_at) DESC, datetime(ns.created_at) DESC`
    ).bind(NS_SETTING_GEMINI_API_KEY).all() as {
        results?: Array<{ value?: string; updated_at?: string }>
    }

    const keys = normalizeGeminiApiKeyList((rows.results || []).map((row) => row?.value || ''))
    const updatedAt = String(rows.results?.[0]?.updated_at || '').trim() || null
    return { keys, updatedAt }
}

async function clearLegacySystemGeminiApiKeys(db: D1Database): Promise<void> {
    await ensureNamespaceSettingsTable(db)
    await db.prepare(
        `DELETE FROM namespace_settings
         WHERE key = ?
           AND namespace_id IN (
             SELECT DISTINCT u.namespace_id
             FROM users u
             INNER JOIN system_admins sa
               ON lower(trim(sa.email)) = lower(trim(u.email))
             WHERE trim(coalesce(u.namespace_id, '')) <> ''
           )`
    ).bind(NS_SETTING_GEMINI_API_KEY).run()
}

async function getSystemGeminiApiKeyEntries(db: D1Database): Promise<{ keys: string[]; updatedAt: string | null; source: 'system' | 'legacy' | 'none' }> {
    await ensureNamespaceSettingsTable(db)
    const row = await db.prepare(
        'SELECT value, updated_at FROM namespace_settings WHERE namespace_id = ? AND key = ?'
    ).bind(SYSTEM_GEMINI_NAMESPACE_ID, NS_SETTING_GEMINI_API_KEYS).first() as { value?: string; updated_at?: string } | null

    let parsed: unknown = []
    try {
        parsed = JSON.parse(String(row?.value || '[]'))
    } catch {
        parsed = []
    }
    const keys = normalizeGeminiApiKeyList(parsed)
    if (keys.length > 0) {
        return {
            keys,
            updatedAt: String(row?.updated_at || '').trim() || null,
            source: 'system',
        }
    }

    const legacy = await getLegacySystemGeminiApiKeys(db)
    if (legacy.keys.length > 0) {
        return {
            keys: legacy.keys,
            updatedAt: legacy.updatedAt,
            source: 'legacy',
        }
    }

    return {
        keys: [],
        updatedAt: null,
        source: 'none',
    }
}

async function setSystemGeminiApiKeys(db: D1Database, rawKeys: unknown): Promise<void> {
    await ensureNamespaceSettingsTable(db)
    const keys = normalizeGeminiApiKeyList(rawKeys)
    if (keys.length === 0) {
        await db.prepare(
            'DELETE FROM namespace_settings WHERE namespace_id = ? AND key = ?'
        ).bind(SYSTEM_GEMINI_NAMESPACE_ID, NS_SETTING_GEMINI_API_KEYS).run()
        await clearLegacySystemGeminiApiKeys(db)
        return
    }

    await db.prepare(
        `INSERT INTO namespace_settings (namespace_id, key, value, created_at, updated_at)
         VALUES (?, ?, ?, datetime('now'), datetime('now'))
         ON CONFLICT(namespace_id, key)
         DO UPDATE SET value = excluded.value, updated_at = datetime('now')`
    ).bind(
        SYSTEM_GEMINI_NAMESPACE_ID,
        NS_SETTING_GEMINI_API_KEYS,
        JSON.stringify(keys),
    ).run()
}

async function resolveNamespaceGeminiApiKeys(db: D1Database, _namespaceId: string): Promise<string[]> {
    const system = await getSystemGeminiApiKeyEntries(db)
    return system.keys
}

async function resolveNamespaceGeminiApiKey(db: D1Database, namespaceId: string): Promise<string> {
    const keys = await resolveNamespaceGeminiApiKeys(db, namespaceId)
    return keys[0] || ''
}

async function getNamespaceGeminiApiKeySettings(db: D1Database, _namespaceId: string) {
    const system = await getSystemGeminiApiKeyEntries(db)
    return {
        has_key: system.keys.length > 0,
        keys_count: system.keys.length,
        masked_key: maskApiKeyForDisplay(system.keys[0] || ''),
        masked_keys: system.keys.map((key) => maskApiKeyForDisplay(key)),
        source: system.source,
        updated_at: system.updatedAt,
    }
}

